"use client";

import { useEffect, useState } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import Link from "next/link";
import { api, type Category, type MenuOptionGroup, type DrinkSizesResponse, type MenuSize, normalizeSubCategories } from "@/lib/api";

export default function NewItemPage() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [name, setName] = useState("");
  const [pricePesos, setPricePesos] = useState("");
  const [categoryId, setCategoryId] = useState("");
  const [subCategoryId, setSubCategoryId] = useState("");
  const [isActive, setIsActive] = useState(true);
  const [categories, setCategories] = useState<Category[]>([]);
  const [optionGroups, setOptionGroups] = useState<MenuOptionGroup[]>([]);
  const [selectedGroupIds, setSelectedGroupIds] = useState<string[]>([]);
  const [drinkSizes, setDrinkSizes] = useState<DrinkSizesResponse | null>(null);
  const [drinkSizesError, setDrinkSizesError] = useState<string | null>(null);
  const [defaultSizeOptionId, setDefaultSizeOptionId] = useState("");
  const [menuSizes, setMenuSizes] = useState<MenuSize[]>([]);
  const [sizeAvailability, setSizeAvailability] = useState<{
    ICED: string[];
    HOT: string[];
    CONCENTRATED: string[];
  }>({
    ICED: [],
    HOT: [],
    CONCENTRATED: [],
  });
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const presetSubCategoryId = searchParams.get("subCategoryId") ?? "";
  const presetCategoryId = searchParams.get("categoryId") ?? "";

  useEffect(() => {
    Promise.all([api.getCategories(), api.getOptionGroups()])
      .then(([cats, groups]) => {
        const safeCats = Array.isArray(cats) ? cats : [];
        setCategories(safeCats);
        setOptionGroups(Array.isArray(groups) ? groups : []);
        if (presetSubCategoryId && safeCats.length > 0) {
          for (const cat of safeCats) {
            const subs = normalizeSubCategories(cat.subCategories);
            const sub = subs.find((s) => s.id === presetSubCategoryId);
            if (sub) {
              setCategoryId(cat.id);
              setSubCategoryId(sub.id);
              break;
            }
          }
        } else if (presetCategoryId && safeCats.some((c) => c.id === presetCategoryId)) {
          setCategoryId(presetCategoryId);
        }
      })
      .catch(() => {
        setCategories([]);
        setOptionGroups([]);
      });
  }, [presetSubCategoryId, presetCategoryId]);

  useEffect(() => {
    Promise.all([api.getDrinkSizes(), api.getMenuSizes()])
      .then(([sizesFromOptions, menuSizesResult]) => {
        setDrinkSizes(sizesFromOptions);
        setMenuSizes(menuSizesResult.sizes ?? []);
        if (menuSizesResult.availability) {
          setSizeAvailability({
            ICED: menuSizesResult.availability.ICED ?? [],
            HOT: menuSizesResult.availability.HOT ?? [],
            CONCENTRATED: menuSizesResult.availability.CONCENTRATED ?? [],
          });
        }
      })
      .catch(() => {
        setDrinkSizesError(
          "Missing drink size configuration. Run db:seed in cloud-api and configure Menu Settings → Sizes."
        );
      });
  }, []);

  function handleImageChange(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0] ?? null;
    setImageFile(file);
    setImagePreview((prev) => {
      if (prev) URL.revokeObjectURL(prev);
      return file ? URL.createObjectURL(file) : null;
    });
  }

  useEffect(() => {
    return () => {
      if (imagePreview) URL.revokeObjectURL(imagePreview);
    };
  }, [imagePreview]);

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError("");
    const peso = parseFloat(pricePesos);
    if (Number.isNaN(peso) || peso < 0) {
      setError("Price must be a non-negative number.");
      return;
    }
    if (!categoryId || !subCategoryId) {
      setError("Category and subcategory are required.");
      return;
    }
    const priceCents = Math.round(peso * 100);
    setLoading(true);
    try {
      const item = await api.createItem({
        name,
        priceCents,
        isActive,
        subCategoryId,
        defaultSizeOptionId: defaultSizeOptionId || null,
      });
      if (imageFile) {
        await api.uploadItemImage(item.id, imageFile);
      }
      if (selectedGroupIds.length > 0) {
        await api.putItemOptionGroups(item.id, selectedGroupIds);
      }
      router.replace("/menu");
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to create item");
    } finally {
      setLoading(false);
    }
  }

  function toggleOptionGroup(groupId: string) {
    setSelectedGroupIds((prev) =>
      prev.includes(groupId) ? prev.filter((g) => g !== groupId) : [...prev, groupId]
    );
  }

  const safeCategories = Array.isArray(categories) ? categories : [];
  const subCategories = categoryId
    ? normalizeSubCategories(safeCategories.find((c) => c.id === categoryId)?.subCategories)
    : [];
  const canSubmit = !!categoryId && !!subCategoryId;

  return (
    <div className="mx-auto max-w-6xl px-4 py-6">
      <div className="mb-4">
        <Link href="/menu" className="text-gray-500 hover:text-gray-700">← Menu</Link>
      </div>
      <h1 className="mb-4 text-2xl font-semibold">New Item</h1>
      <form onSubmit={handleSubmit} className="max-w-md space-y-4 rounded border bg-white p-4 shadow-sm">
        <div>
          <label className="mb-1 block text-sm font-medium text-gray-700">Image</label>
          <div className="flex items-start gap-3">
            {imagePreview ? (
              <img src={imagePreview} alt="" className="h-20 w-20 rounded object-cover border border-gray-200" />
            ) : (
              <div className="flex h-20 w-20 items-center justify-center rounded border border-dashed border-gray-300 bg-gray-50 text-gray-400 text-xs">
                Preview
              </div>
            )}
            <div>
              <input
                type="file"
                accept="image/*"
                onChange={handleImageChange}
                className="text-sm"
              />
              {imageFile && <p className="mt-1 text-xs text-gray-500">{imageFile.name}</p>}
            </div>
          </div>
        </div>
        <div>
          <label className="mb-1 block text-sm font-medium text-gray-700">Name</label>
          <input
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            required
            className="w-full rounded border border-gray-300 px-3 py-2 focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
          />
        </div>
        <div>
          <label className="mb-1 block text-sm font-medium text-gray-700">Price (₱)</label>
          <input
            type="number"
            min={0}
            step="0.01"
            value={pricePesos}
            onChange={(e) => setPricePesos(e.target.value)}
            required
            className="w-full rounded border border-gray-300 px-3 py-2 focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
          />
        </div>
        <div>
          <label className="mb-1 block text-sm font-medium text-gray-700">Category</label>
          <select
            value={categoryId}
            onChange={(e) => {
              setCategoryId(e.target.value);
              setSubCategoryId("");
            }}
            className="w-full rounded border border-gray-300 px-3 py-2 focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
          >
            <option value="">Select category</option>
            {safeCategories.map((c) => (
              <option key={c.id} value={c.id}>{c.name}</option>
            ))}
          </select>
        </div>
        <div>
          <label className="mb-1 block text-sm font-medium text-gray-700">Subcategory <span className="text-red-500">*</span></label>
          <select
            value={subCategoryId}
            onChange={(e) => setSubCategoryId(e.target.value)}
            required
            className="w-full rounded border border-gray-300 px-3 py-2 focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
          >
            <option value="">{categoryId ? "Select subcategory" : "Select a category first"}</option>
            {subCategories.map((sc) => (
              <option key={sc.id} value={sc.id}>{sc.name}</option>
            ))}
          </select>
          {categoryId && subCategories.length === 0 && (
            <p className="mt-1 text-xs text-amber-600">No subcategories. Create one in Categories.</p>
          )}
        </div>

        <div className="rounded border border-gray-200 bg-gray-50 p-3">
          <label className="mb-2 block text-sm font-medium text-gray-700">Default size (optional)</label>
          <p className="mb-2 text-xs text-gray-500">
            From Menu Settings → Sizes. This is the default size for the POS when this item is selected.
          </p>
          {drinkSizesError && (
            <div className="rounded border border-amber-300 bg-amber-50 p-3">
              <p className="mb-2 text-sm font-medium text-amber-800">{drinkSizesError}</p>
              <Link
                href="/menu-settings/sizes"
                className="inline-block rounded bg-amber-600 px-3 py-1.5 text-sm text-white hover:bg-amber-700"
              >
                Go to Menu Settings → Sizes
              </Link>
            </div>
          )}
          {drinkSizes && drinkSizes.options.length > 0 && menuSizes.length > 0 && (
            <select
              value={defaultSizeOptionId}
              onChange={(e) => setDefaultSizeOptionId(e.target.value)}
              className="w-full rounded border border-gray-300 px-2 py-1.5 text-sm"
            >
              <option value="">None</option>
              {(() => {
                // Build a set of labels that are available in at least one mode from Menu Settings
                const allIds = new Set<string>();
                ["ICED", "HOT", "CONCENTRATED"].forEach((mode) => {
                  const list = (sizeAvailability as any)[mode] as string[] | undefined;
                  (list ?? []).forEach((id) => allIds.add(id));
                });
                const labelById = new Map(menuSizes.map((s) => [s.id, s.label]));
                const allowedLabels = new Set(
                  Array.from(allIds)
                    .map((id) => labelById.get(id))
                    .filter((label): label is string => !!label)
                );

                const options = drinkSizes.options.filter((o) =>
                  allowedLabels.size > 0 ? allowedLabels.has(o.label) : true
                );

                return options.map((o) => (
                  <option key={o.id} value={o.id}>
                    {o.label}
                  </option>
                ));
              })()}
            </select>
          )}
        </div>

        <div>
          <label className="mb-2 block text-sm font-medium text-gray-700">Option Groups</label>
          <div className="flex flex-wrap gap-2">
            {optionGroups.map((g) => (
              <label key={g.id} className="flex items-center gap-2 rounded border border-gray-200 px-3 py-2 text-sm hover:bg-gray-50">
                <input
                  type="checkbox"
                  checked={selectedGroupIds.includes(g.id)}
                  onChange={() => toggleOptionGroup(g.id)}
                  className="rounded border-gray-300"
                />
                {g.name}
              </label>
            ))}
            {optionGroups.length === 0 && (
              <span className="text-gray-500 text-sm">No option groups. Add them in Options.</span>
            )}
          </div>
        </div>
        <div className="flex items-center gap-2">
          <input
            type="checkbox"
            id="isActive"
            checked={isActive}
            onChange={(e) => setIsActive(e.target.checked)}
            className="rounded border-gray-300"
          />
          <label htmlFor="isActive" className="text-sm text-gray-700">Active</label>
        </div>
        {error && <p className="rounded border border-red-200 bg-red-50 px-3 py-2 text-sm text-red-700">{error}</p>}
        <div className="flex gap-2">
          <button
            type="submit"
            disabled={loading || !canSubmit}
            className="rounded bg-blue-600 px-4 py-2 text-white hover:bg-blue-700 disabled:opacity-50"
          >
            {loading ? "Creating…" : "Create"}
          </button>
          <Link href="/menu" className="rounded border border-gray-300 px-4 py-2 text-gray-700 hover:bg-gray-50">
            Cancel
          </Link>
        </div>
      </form>
    </div>
  );
}
